import React from 'react';
import { Category, ShirtVersion } from '../types';
import ProductCard from './ProductCard';
import ShirtVersionCard from './ShirtVersionCard';
import { getImagePath } from '../utils';

interface CategorySectionProps {
  category: Category;
  quantities: Record<string, string>;
  shirtVersions?: Record<string, ShirtVersion>;
  onQuantityChange?: (imagePath: string, value: string) => void;
  onShirtVersionChange?: (imagePath: string, version: keyof ShirtVersion, value: string) => void;
  readOnly?: boolean;
}

const CategorySection: React.FC<CategorySectionProps> = ({
  category,
  quantities,
  shirtVersions = {},
  onQuantityChange,
  onShirtVersionChange,
  readOnly = false
}) => {
  return (
    <section style={{ marginBottom: '2rem', background: 'var(--color-bg-alt)', borderRadius: 'var(--radius)', padding: 'var(--space-3)' }}>
      <h2 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-2)' }}>{category.name}</h2>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--space-2)' }}>
        {category.images.map((img) => {
          const imagePath = getImagePath(category.path, img);

          if (category.hasShirtVersions) {
            const shirtVersion = shirtVersions[imagePath] || { tshirt: '', longsleeve: '', hoodie: '' };

            return (
              <ShirtVersionCard
                key={img}
                categoryPath={category.path}
                imageName={img}
                shirtVersions={shirtVersion}
                onShirtVersionChange={onShirtVersionChange}
                readOnly={readOnly}
              />
            );
          } else {
            const quantity = quantities[imagePath] || '';

            return (
              <ProductCard
                key={img}
                categoryPath={category.path}
                imageName={img}
                quantity={quantity}
                onQuantityChange={onQuantityChange}
                readOnly={readOnly}
              />
            );
          }
        })}
      </div>
    </section>
  );
};

export default CategorySection;
